Actionscript.script:
stop();

Setting.visible = false;
backdrop.visible = false;

BtnMateri.addEventListener("click", function() {
		gotoAndPlay(1, "Halaman Materi")
});

BtnTentang.addEventListener("click", function(){
	gotoAndPlay(1, "Halaman Tentang");
});

BtnSettings.addEventListener("click", function() {
	if (!Setting.visible) {
		Setting.visible = true;
		backdrop.visible = true;
	}
});

backdrop.addEventListener("click", function() {
	Setting.visible = false;
	backdrop.visible = false;
});

stop();

BtnBack.addEventListener("click", function() {
	gotoAndPlay(1, "Halaman Menu Utama");
});

Chapter1.addEventListener("click", function() {
	gotoAndPlay(2);
});

Chapter2.addEventListener("click", function() {
	gotoAndPlay(3);
});

Chapter3.addEventListener("click", function() {
	gotoAndPlay(4);
});

stop();

BtnBack.addEventListener("click", function() {
	gotoAndPlay(1);
});

Next1.addEventListener("click", function() {
	gotoAndPlay(3);
});

stop();

BtnBack.addEventListener("click", function() {
	gotoAndPlay(1);
});

Prev2.addEventListener("click", function() {
	gotoAndPlay(2);
});

Next2.addEventListener("click", function() {
	gotoAndPlay(4);
});

stop();

BtnBack.addEventListener("click", function() {
	gotoAndPlay(1);
});

Prev3.addEventListener("click", function() {
	gotoAndPlay(3);
});

Next3.addEventListener("click", function() {
	gotoAndPlay(1);
	// Ini langsung ke kuis, ingfokan ketika sudah ada
});

stop();

BtnMenu.addEventListener("click", function() {
	gotoAndPlay(1, "Halaman Menu Utama");
});
